import "./scroll-area.css";

import { ScrollArea } from "radix-ui";
import { cn } from "tailwind-variants";

import { scrollAreaVariants } from "./scroll-area.variants";

export type ScrollAreaProps = React.ComponentProps<typeof ScrollArea.Root>;

export const ScrollAreaRoot = ({ children, className, ...props }: ScrollAreaProps) => {
  const { corner, root, scrollbar, thumb, viewport } = scrollAreaVariants();

  return (
    <ScrollArea.Root className={cn(root(), className)} {...props}>
      <ScrollArea.Viewport className={viewport()}>{children}</ScrollArea.Viewport>
      <ScrollArea.Scrollbar className={scrollbar()} orientation="vertical">
        <ScrollArea.Thumb className={thumb()} />
      </ScrollArea.Scrollbar>
      <ScrollArea.Scrollbar className={scrollbar()} orientation="horizontal">
        <ScrollArea.Thumb className={thumb()} />
      </ScrollArea.Scrollbar>
      <ScrollArea.Corner className={corner()} />
    </ScrollArea.Root>
  );
};

import { tv, type VariantProps } from "tailwind-variants";

export const scrollAreaVariants = tv({
  slots: {
    corner: "scroll-area__corner",
    root: "scroll-area",
    scrollbar: "scroll-area__scrollbar",
    thumb: "scroll-area__thumb",
    viewport: "scroll-area__viewport",
  },
});

export type ScrollAreaVariants = VariantProps<typeof scrollAreaVariants>;

.scroll-area {
  @apply relative overflow-hidden;
}

.scroll-area__viewport {
  @apply size-full rounded-[inherit];
}

.scroll-area__scrollbar {
  @apply flex touch-none p-0.5 transition-colors select-none;

  &[data-orientation="vertical"] {
    @apply h-full w-2.5 border-l border-l-transparent;
  }

  &[data-orientation="horizontal"] {
    @apply h-2.5 flex-col border-t border-t-transparent;
  }

  &:hover {
    @apply bg-border;
  }
}

.scroll-area__thumb {
  @apply bg-border relative flex-1 rounded-full;

  &::before {
    @apply absolute top-1/2 left-1/2 size-full min-h-11 min-w-11 -translate-x-1/2 -translate-y-1/2;
    content: "";
  }
}

.scroll-area__corner {
  @apply bg-border;
}

import { ScrollAreaRoot } from "./scroll-area";

export const ScrollArea = {
  Root: ScrollAreaRoot,
};

export { ScrollAreaRoot };

export type { ScrollAreaProps } from "./scroll-area";

export { type ScrollAreaVariants, scrollAreaVariants } from "./scroll-area.variants";
